// ============================================================
// HydraNet - Utility Managers API Route
// Dedicated endpoint for UtilityManager table operations
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { hashPassword, checkEmailUniqueness } from '@/lib/auth'
import { EntityStatus } from '@prisma/client'

// GET /api/utility-managers - List all utility managers
export async function GET(request: NextRequest) {
  try {
    const managers = await prisma.utilityManager.findMany({
      include: {
        utility: { select: { id: true, name: true } },
      },
      orderBy: { name: 'asc' },
    })

    // Transform to include utilityId/utilityName at top level for compatibility
    const transformedManagers = managers.map((manager) => ({
      id: manager.id,
      name: manager.name,
      email: manager.email,
      phone: manager.phone,
      avatar: manager.avatar,
      status: manager.status,
      role: 'utility_manager',
      utilityId: manager.utilityId,
      utilityName: manager.utility?.name || null,
      createdAt: manager.createdAt,
      updatedAt: manager.updatedAt,
    }))

    return NextResponse.json(transformedManagers)
  } catch (error) {
    console.error('Error fetching utility managers:', error)
    return NextResponse.json({ error: 'Failed to fetch utility managers' }, { status: 500 })
  }
}

// POST /api/utility-managers - Create a new utility manager
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Validate required fields
    if (!data.name || !data.email || !data.utilityId) {
      return NextResponse.json(
        { error: 'Name, email, and utilityId are required' },
        { status: 400 }
      )
    }

    // Check email uniqueness across all user tables
    const emailCheck = await checkEmailUniqueness(data.email)
    if (!emailCheck.isUnique) {
      return NextResponse.json(
        { error: `This email is already in use by a ${emailCheck.foundIn}` },
        { status: 400 }
      )
    }

    // Check if utility already has a manager
    const existingManagerForUtility = await prisma.utilityManager.findFirst({
      where: { utilityId: data.utilityId },
    })

    if (existingManagerForUtility) {
      return NextResponse.json(
        { error: 'This utility already has a manager assigned' },
        { status: 400 }
      )
    }

    // Hash the password
    const hashedPassword = await hashPassword(data.password || 'utility123')

    // Create the utility manager
    const manager = await prisma.utilityManager.create({
      data: {
        name: data.name,
        email: data.email,
        password: hashedPassword,
        phone: data.phone || null,
        avatar: data.avatar || null,
        status: data.status || 'active',
        utilityId: data.utilityId,
      },
      include: {
        utility: { select: { id: true, name: true } },
      },
    })

    return NextResponse.json({
      id: manager.id,
      name: manager.name,
      email: manager.email,
      phone: manager.phone,
      avatar: manager.avatar,
      status: manager.status,
      role: 'utility_manager',
      utilityId: manager.utilityId,
      utilityName: manager.utility?.name || null,
      createdAt: manager.createdAt,
      updatedAt: manager.updatedAt,
    }, { status: 201 })
  } catch (error) {
    console.error('Error creating utility manager:', error)
    return NextResponse.json({ error: 'Failed to create utility manager' }, { status: 500 })
  }
}

// PUT /api/utility-managers - Update a utility manager
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id) {
      return NextResponse.json({ error: 'Utility Manager ID is required' }, { status: 400 })
    }

    // Check email uniqueness across all user tables (excluding current manager)
    if (data.email) {
      const emailCheck = await checkEmailUniqueness(data.email, data.id)
      if (!emailCheck.isUnique) {
        return NextResponse.json(
          { error: `This email is already in use by a ${emailCheck.foundIn}` },
          { status: 400 }
        )
      }
    }

    // Get current manager to check if utilityId is changing
    const currentManager = await prisma.utilityManager.findUnique({
      where: { id: data.id },
    })

    if (!currentManager) {
      return NextResponse.json({ error: 'Utility Manager not found' }, { status: 404 })
    }

    // Build update data
    const updateData: {
      name: string
      email: string
      phone: string | null
      avatar: string | null
      status: EntityStatus
      password?: string
      utility?: { disconnect: true } | { connect: { id: string } }
    } = {
      name: data.name,
      email: data.email,
      phone: data.phone || null,
      avatar: data.avatar || null,
      status: data.status as EntityStatus,
    }

    // Only update password if provided
    if (data.password) {
      updateData.password = await hashPassword(data.password)
    }

    // Check if utilityId is being changed (including unassignment to null)
    if (data.utilityId !== undefined && data.utilityId !== currentManager.utilityId) {
      // If assigning to a new utility (not null)
      if (data.utilityId !== null) {
        // Check if the new utility already has a manager
        const existingManagerForUtility = await prisma.utilityManager.findFirst({
          where: { utilityId: data.utilityId, id: { not: data.id } },
        })

        if (existingManagerForUtility) {
          return NextResponse.json(
            { error: 'This utility already has a manager assigned' },
            { status: 400 }
          )
        }

        // Connect to the new utility
        updateData.utility = { connect: { id: data.utilityId } }
      } else {
        // Disconnect from utility (unassign)
        updateData.utility = { disconnect: true }
      }
    }

    // Update password if provided
    if (data.password) {
      const hashedPassword = await hashPassword(data.password)
      await prisma.$executeRaw`
        UPDATE "UtilityManager" 
        SET 
          name = ${data.name},
          email = ${data.email},
          phone = ${data.phone || null},
          avatar = ${data.avatar || null},
          status = ${data.status}::"EntityStatus",
          "utilityId" = ${data.utilityId},
          password = ${hashedPassword},
          "updatedAt" = NOW()
        WHERE id = ${data.id}
      `
    } else {
      await prisma.$executeRaw`
        UPDATE "UtilityManager" 
        SET 
          name = ${data.name},
          email = ${data.email},
          phone = ${data.phone || null},
          avatar = ${data.avatar || null},
          status = ${data.status}::"EntityStatus",
          "utilityId" = ${data.utilityId},
          "updatedAt" = NOW()
        WHERE id = ${data.id}
      `
    }

    // Fetch the updated manager with utility relation
    const updatedManager = await prisma.utilityManager.findUnique({
      where: { id: data.id },
      include: {
        utility: { select: { id: true, name: true } },
      },
    })

    return NextResponse.json({
      id: updatedManager?.id,
      name: updatedManager?.name,
      email: updatedManager?.email,
      phone: updatedManager?.phone,
      avatar: updatedManager?.avatar,
      status: updatedManager?.status,
      role: 'utility_manager',
      utilityId: updatedManager?.utilityId,
      utilityName: updatedManager?.utility?.name || null,
      createdAt: updatedManager?.createdAt,
      updatedAt: updatedManager?.updatedAt,
    })
  } catch (error) {
    console.error('Error updating utility manager:', error)
    const errorMessage = error instanceof Error ? error.message : 'Failed to update utility manager'
    return NextResponse.json({ error: errorMessage }, { status: 500 })
  }
}

// DELETE /api/utility-managers - Delete a utility manager
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')

    if (!id) {
      return NextResponse.json({ error: 'Utility Manager ID is required' }, { status: 400 })
    }

    await prisma.utilityManager.delete({
      where: { id },
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error deleting utility manager:', error)
    return NextResponse.json({ error: 'Failed to delete utility manager' }, { status: 500 })
  }
}